  ('judicial-f0899a01-moex-00512', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '關於刑法第10條第2項有關「公務員」之定義規定，下列敘述何者錯誤？', '["代收各項政府機關稅收的便利商店人員，不是刑法上的公務員", "公立大學教授接受政府委託，從事研究計畫並為相關採購事務，不是刑法上的公務員", "在司法院服務的工友，不是刑法上的公務員", "受公路主管機關委託辦理汽車定期檢驗的汽車修理業者，不是刑法上的公務員"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:47+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00513', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲與乙一同飲酒作樂後，甲搭乘乙駕駛之車輛回家，因乙不勝酒力，失控撞上丙，丙當場死亡，警察到場 後，甲向警察自稱為乙，且承認自己駕車撞死丙。甲之行為，應評價為刑法的何種行為？', '["頂替行為", "誣告行為", "中止行為", "自白行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:47+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00514', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲違法排放有毒污水於河流中，案發後甲立即湮滅相關證據，甲是否構成刑法第165條之湮滅刑事證據罪？', '["不成立本罪", "成立本罪，且行為惡性重大，不能減免刑責", "成立本罪，但若自白，得減輕或免除其刑", "成立本罪，但欠缺期待可能性，得減輕其刑"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:47+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00515', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '警察甲受好友A之託，使用自己合法帳號進入國家電腦資訊查詢系統，從中查得B之個人戶政資料，再 將之交付給A。甲之行為，成立何罪？', '["第109條洩漏國防秘密罪", "第132條洩漏國防以外秘密罪", "第316條洩漏業務秘密罪", "第358條無故入侵電腦罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:47+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL)
